const items = $input.all();

if (!items.length) {
  return [];
}

// Nichos sao informados manualmente (ex: tabela nichos).
// Processa todos os nichos recebidos, sem sorteio aleatorio.
return items
  .map((item) => ({ json: { nicho_alvo: item.json.slug } }))
  .filter((item) => !!item.json.nicho_alvo);

const sd = $getWorkflowStaticData('global');
sd.currentChannel = {
  canal_id: $json.canal_id,
  nome_canal: $json.nome_canal,
  nicho_alvo: $json.nicho_alvo
};
return $input.all();

// Trata canal_id como UC real ou handle para resolver pela API
const raw = String($json.canal_id || '').trim();
const cleaned = raw.replace('@', '');
const isUcId = /^UC[a-zA-Z0-9_-]{22}$/.test(cleaned);

return [{
  json: {
    ...$json,
    is_handle: !isUcId,
    handle_lookup: cleaned,
  }
}];

// Extrai channelId real do resultado da API
const items = $json.items || [];
const channelId = items.length > 0 ? items[0].id : '';

const sd = $getWorkflowStaticData('global');
sd.currentChannel.channel_id_real = channelId;

return [{ json: { channel_id_real: channelId } }];

// canal_id já é UCxxxx, passa direto
const sd = $getWorkflowStaticData('global');
sd.currentChannel.channel_id_real = $json.canal_id;

return [{ json: { channel_id_real: $json.canal_id } }];

// Monta lista de video IDs para busca de detalhes
const items = $json.items || [];
const videoIds = items
  .filter(i => i.id && i.id.videoId)
  .map(i => i.id.videoId);

if (!videoIds.length) return [];

return [{ json: { video_ids: videoIds.join(',') } }];

const sd = $getWorkflowStaticData('global');
const canal = sd.currentChannel || {};

const data = $input.first().json;
const items = data.items || [];

const parseDuration = (iso) => {
  const m = iso.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!m) return 0;

  return (parseInt(m[1] || 0) * 3600) +
         (parseInt(m[2] || 0) * 60) +
         parseInt(m[3] || 0);
};

const esc = (s) =>
  String(s || '').replace(/'/g, "''").substring(0, 500);

const results = [];

for (const item of items) {

  if (results.length >= 10) break; // ✅ limite 10

  const video_id = item.id;
  if (!video_id || !/^[a-zA-Z0-9_-]{11}$/.test(video_id)) continue;

  const stats   = item.statistics || {};
  const details = item.contentDetails || {};
  const snippet = item.snippet || {};

  const durSec = parseDuration(details.duration || 'PT0S');

  const views       = parseInt(stats.viewCount || 0);
  const likes       = parseInt(stats.likeCount || 0);
  const comentarios = parseInt(stats.commentCount || 0);

  const engagement =
    views > 0
      ? parseFloat(((likes + comentarios) / views * 100).toFixed(2))
      : 0;

  results.push({
    json: {
      canal_id: esc(canal.canal_id || ''),
      nicho: esc(canal.nicho_alvo || ''),
      video_id: video_id,
      url_video: `https://www.youtube.com/watch?v=${video_id}`,
      titulo: esc(snippet.title || ''),
      duracao_segundos: durSec,
      views: views,
      likes: likes,
      comentarios: comentarios,
      engagement_pct: engagement,
      thumbnail_url: `https://i.ytimg.com/vi/${video_id}/hqdefault.jpg`
    }
  });
}

return results;

